import * as THREE from 'three';
import WebGLBase from './core/WebGLBase';
import MapManager from './systems/MapManager';
import EquipmentManager from './systems/EquipmentManager';
import InteractionManager from './systems/InteractionManager';
import LightingSystem from './systems/LightingSystem';
import { TransformControls } from 'three/examples/jsm/controls/TransformControls.js';

/**
 * QuarantineThreeEngine: 3D 시뮬레이션의 메인 엔진
 * 맵 로딩, 장비 배치, 카메라 연출 및 실시간 HUD를 총괄합니다.
 */
export default class QuarantineThreeEngine extends WebGLBase {
  public mapManager: MapManager;
  public equipmentManager: EquipmentManager;
  public interaction: InteractionManager;
  public lighting: LightingSystem;

  private debugHelpers: THREE.Group = new THREE.Group();
  
  // HUD 전광판 전용
  private uiScene: THREE.Scene = new THREE.Scene();
  private uiCamera: THREE.OrthographicCamera;
  private hudSprite: THREE.Sprite | null = null;
  private hudCanvas = document.createElement('canvas');
  private showDebug: boolean = false;
  private isEditMode: boolean = false;

  constructor(container: HTMLElement) {
    super(container);
    
    this.mapManager = new MapManager(this.scene);
    this.equipmentManager = new EquipmentManager(this.scene);
    this.interaction = new InteractionManager(this.camera, container);
    this.lighting = new LightingSystem(this.scene);

    // UI 전용 카메라 설정
    const aspect = container.clientWidth / container.clientHeight;
    this.uiCamera = new THREE.OrthographicCamera(-aspect, aspect, 1, -1, 0.1, 10);
    this.uiCamera.position.z = 1;

    this.startRendering();
  }

  /**
   * 장비에 이동 기즈모 부착
   */
  public attachGizmo(object: THREE.Object3D) {
    if (!this.isEditMode) return;
    this.interaction.attach(object);
  }

  /**
   * 기즈모 분리
   */
  public detachGizmo() {
    this.interaction.detach();
  }

  public async loadAllAssets(modelFile: string, devices: any[], mapBaseUrl: string, equipBaseUrl: string) {
    console.log("[Engine] Starting Multi-Path Asset Load...");
    await this.mapManager.loadMap(modelFile, mapBaseUrl);
    await this.equipmentManager.loadDevices(devices, equipBaseUrl);
    
    // 첫 번째 시도
    this.fitView();
    
    // 0.3초 뒤 두 번째 시도 (비동기 메시 업데이트 대응)
    setTimeout(() => {
        console.log("[Engine] Retrying FitView for stability...");
        this.fitView();
    }, 300);
  }

  public fitView() {
    console.log("[Engine] fitView() Requested.");
    
    // [PRIORITY-CHECK] 이미 장비 선택 등으로 전이 중이라면 맵 전체 보기가 이를 방해하지 않도록 함
    if (this.interaction.isTransitioning) {
        console.log("[Engine] Skipping fitView as a manual transition is already in progress.");
        return;
    }

    const strictBox = this.mapManager.calculateStrictBounds();
    if (strictBox.isEmpty()) {
        console.warn("[Engine] strictBox is EMPTY! Skipping fitView.");
        return;
    }

    const size = new THREE.Vector3();
    strictBox.getSize(size);
    
    const aspect = this.camera.aspect;
    const fovY = (this.camera.fov * Math.PI) / 180;
    const fovX = 2 * Math.atan(Math.tan(fovY / 2) * aspect);

    const distFitHeight = (size.z / 2) / Math.tan(fovY / 2);
    const distFitWidth = (size.x / 2) / Math.tan(fovX / 2);

    let idealDist = Math.max(distFitHeight, distFitWidth);
    console.log(`[Engine] Fitting: Size(${size.x.toFixed(1)}, ${size.z.toFixed(1)}), Aspect: ${aspect.toFixed(2)}`);
    console.log(`[Engine] Calculated idealDist: ${idealDist.toFixed(1)}`);
    
    idealDist *= 1.15;
    
    console.log(`[Engine] Calling interaction.jumpTo with dist: ${idealDist.toFixed(1)}`);
    this.interaction.jumpTo(0, 0, 0, idealDist, 0);
  }

  /**
   * 장비 뷰 전환: 장비 크기에 맞춰 정밀하게 줌인하고 좌측 명당 자리에 배치
   */
  public lookAtDevice(x: number, y: number, z: number, id: string) {
    const devices = this.getDeviceObjects();
    const target = devices.find(d => d.userData?.id === id);
    
    let idealDist = 120; // fallback

    if (target) {
        // 1. 장비의 실제 크기 측정
        const box = new THREE.Box3().setFromObject(target);
        const size = new THREE.Vector3();
        box.getSize(size);
        const radius = Math.max(size.x, size.y, size.z) / 2;

        // 2. 화면에 너무 꽉 차지 않게 여유롭게 거리 산출 (2.5배 여유)
        const fovRad = (this.camera.fov * Math.PI) / 180;
        idealDist = (radius / Math.tan(fovRad / 2)) * 2.5;
        
        console.log(`[Engine] Focused Device Size: ${radius.toFixed(1)}, Calculated Dist: ${idealDist.toFixed(1)}`);
    }

    // 3. 적절한 좌측 오프셋 (8 정도가 명당 자리)
    this.interaction.jumpTo(x, y, z, idealDist, 10);
  }

  public trackDevice(x: number, y: number, z: number) {
    this.interaction.trackTo(x, y, z, 10);
  }

  public zoom(factor: number) {
    const controls = this.interaction.controls;
    if (factor > 1) {
      controls.dollyIn(factor);
    } else {
      controls.dollyOut(1 / factor);
    }
    controls.update();
  }

  public pick(pointer: THREE.Vector2, objects: THREE.Object3D[]) {
    return this.interaction.pick(pointer, objects);
  }

  public getDeviceObjects() {
    return this.equipmentManager.getDeviceObjects();
  }

  /**
   * HUD 전광판 생성 (가독성 높은 캔버스 텍스처)
   */
  private updateHUD() {
    if (!this.hudSprite) {
        this.hudCanvas.width = 512;
        this.hudCanvas.height = 256;
        const texture = new THREE.CanvasTexture(this.hudCanvas);
        const material = new THREE.SpriteMaterial({ map: texture, transparent: true, depthTest: false });
        this.hudSprite = new THREE.Sprite(material);
        this.hudSprite.scale.set(0.6, 0.3, 1);
        this.hudSprite.position.set(0.6, -0.7, 0); // 우측 하단 고정
        this.uiScene.add(this.hudSprite);
    }

    const ctx = this.hudCanvas.getContext('2d');
    if (!ctx) return;

    const info = this.interaction.debugInfo;
    ctx.clearRect(0, 0, 512, 256);
    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.beginPath();
    ctx.roundRect(0, 0, 512, 256, 30);
    ctx.fill();
    ctx.strokeStyle = '#38bdf8';
    ctx.lineWidth = 12;
    ctx.stroke();

    ctx.font = 'bold 38px Inter, Arial';
    ctx.fillStyle = '#38bdf8';
    ctx.fillText('CAMERA TELEMETRY', 40, 60);
    
    ctx.font = '30px monospace';
    ctx.fillStyle = '#cbd5e1';
    ctx.fillText(`P: ${info.pos.x.toFixed(0)}, ${info.pos.y.toFixed(0)}, ${info.pos.z.toFixed(0)}`, 40, 105);
    ctx.fillText(`T: ${info.target.x.toFixed(0)}, ${info.target.y.toFixed(0)}, ${info.target.z.toFixed(0)}`, 40, 150);
    
    ctx.fillStyle = this.interaction.isTransitioning ? '#22c55e' : '#ef4444';
    ctx.fillText(`TR: ${this.interaction.isTransitioning ? 'RUNNING' : 'STOPPED'}`, 40, 195);

    ctx.fillStyle = '#fde047';
    ctx.font = 'bold 44px Arial';
    ctx.fillText(`DIST: ${info.dist.toFixed(1)}`, 40, 245);
    
    (this.hudSprite.material as any).map.needsUpdate = true;
  }

  public setEditMode(isEdit: boolean) {
    this.isEditMode = isEdit;
    this.interaction.setEditMode(isEdit);
    if (!isEdit) this.detachGizmo();
    console.log(`[Engine] Edit Mode: ${isEdit}`);
  }

  public setDebugMode(show: boolean) {
    this.showDebug = show;
    this.scene.remove(this.debugHelpers);
    this.debugHelpers.clear();

    if (show) {
      if (this.mapManager.mapModel) {
        this.debugHelpers.add(new THREE.BoxHelper(this.mapManager.mapModel, 0xffff00));
      }
      this.equipmentManager.getDeviceObjects().forEach(d => {
        this.debugHelpers.add(new THREE.BoxHelper(d, 0x00ff00));
      });
      this.scene.add(this.debugHelpers);
    } else {
        this.uiScene.clear();
        this.hudSprite = null;
    }
  }

  private startRendering() {
    const animate = () => {
      requestAnimationFrame(animate);
      this.interaction.update();
      this.renderer.render(this.scene, this.camera);
      
      // HUD가 켜져있으면 독립된 카메라로 그린 뒤 덮어씌움 (절대 안짤림)
      if (this.showDebug) {
          this.updateHUD();
          this.renderer.autoClear = false;
          this.renderer.clearDepth();
          this.renderer.render(this.uiScene, this.uiCamera);
          this.renderer.autoClear = true;
      }

      this.interaction.renderGizmo(this.renderer);
    };
    animate();
  }

  public dispose() {
    super.dispose();
    this.mapManager.dispose();
    this.equipmentManager.dispose();
  }
}
