import React, { useEffect, useRef, useState, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Card, Button, Space, Typography, Tag, Divider, Badge, theme } from "antd";
import * as THREE from "three";
import _ from "lodash";
import { QUARANTINE_DB } from "../../../mocks/db";
import QuarantineThreeEngine from './module/QuarantineThreeEngine';

interface Placement3DPageProps {
  devices: any[];
  selectedEquipment?: any;
  onDeviceSelect?: (device: any) => void;
}

const { Title, Text } = Typography;

const Placement3DPage: React.FC<Placement3DPageProps> = ({ devices, selectedEquipment, onDeviceSelect }) => {
  const { t } = useTranslation(["quarantine"]);
  const { token } = theme.useToken();
  const containerRef = useRef<HTMLDivElement>(null);
  
  const engineRef = useRef<QuarantineThreeEngine | null>(null);
  const pointerRef = useRef(new THREE.Vector2());
  const clickedObjRef = useRef<any>({});
  const preObjRef = useRef<any>({});

  const [aniFlag, setAniFlag] = useState(true);
  const aniFlagRef = useRef(true);
  const [btnContent, setBtnContent] = useState("btnMap");
  const [cameraPoint, setCameraPoint] = useState({ view: "map", id: "" });
  const cameraPointRef = useRef({ view: "map", id: "" });
  
  const [isEditMode, setIsEditMode] = useState(false);
  const isEditModeRef = useRef(false);
  const [showDebug, setShowDebug] = useState(false);

  const lastRenderTime = useRef(0);
  const fpsLimit = 60;
  const inteval = 1;

  const moveListRef = useRef<any[]>([]);

  const colors = useRef({
    white: new THREE.Color(0xffffff),
    yellow: new THREE.Color(0xffff00),
    red: new THREE.Color(0xff0000)
  });

  // [SYNC] 외부에서의 선택 상태 동기화
  useEffect(() => {
    if (!engineRef.current) return;

    if (selectedEquipment) {
      const devices = engineRef.current.getDeviceObjects();
      const target = devices.find(d => d.userData?.id === selectedEquipment.id);
      
      if (target) {
        // [FIX] 동일 장비 반복 선택 시 카메라 연출(Zoom/Rotate) 중복 실행 방지
        if (clickedObjRef.current.id === target.userData.id) return;

        if (clickedObjRef.current.id) {
          changeOriginalColor();
        }
        
        clickedObjRef.current = { id: target.userData.id };
        const baseScale = QUARANTINE_DB.devices.find(d => d.id === target.userData.id)?.scale || 15;
        const highlightScale = baseScale * 1.2;
        target.scale.set(highlightScale, highlightScale, highlightScale);
        
        target.traverse((el: any) => {
          if (el.isMesh && el.material) el.material.color = colors.current.yellow;
        });

        if (!isEditModeRef.current) {
          const device = QUARANTINE_DB.devices.find(d => d.id === target.userData.id);
          if (device) {
            const { offsetX, offsetY, scale, invX, invY } = QUARANTINE_DB.mapCalibration;
            const normX = (device.x - offsetX) / scale * (invX ? -1 : 1);
            const normZ = (device.y - offsetY) / scale * (invY ? -1 : 1);
            engineRef.current.lookAtDevice(normX, 0, normZ, device.id);
            setCameraPoint({ view: "device", id: target.userData.id });
            setBtnContent("btnDevice");
          }
        }
      }
    } else {
      if (clickedObjRef.current.id) {
        btnCameraClick();
      }
    }
  }, [selectedEquipment]);

  useEffect(() => {
    isEditModeRef.current = isEditMode;
    if (engineRef.current) engineRef.current.setEditMode(isEditMode);
  }, [isEditMode]);

  useEffect(() => {
    if (engineRef.current) engineRef.current.setDebugMode(showDebug);
  }, [showDebug]);

  const changeOriginalColor = () => {
    if (!engineRef.current) return;
    const { scene } = engineRef.current;
    scene.children.forEach((el: any) => {
      if (el.userData?.id && el.userData.id === clickedObjRef.current.id) {
        const originalScale = QUARANTINE_DB.devices.find(d => d.id === el.userData.id)?.scale || 15;
        el.scale.set(originalScale, originalScale, originalScale);
        el.traverse((child: any) => {
          if (child.isMesh && child.material) child.material.color = colors.current.white;
        });
      }
    });
  };

  useEffect(() => { aniFlagRef.current = aniFlag; }, [aniFlag]);
  useEffect(() => { cameraPointRef.current = cameraPoint; }, [cameraPoint]);

  // [SIMULATION-SYNC] 가상 서버의 장비 이동 데이터를 3D 엔진의 이동 목표로 실시간 동기화
  useEffect(() => {
    if (!engineRef.current) return;
    const { offsetX, offsetY, scale, invX, invY } = QUARANTINE_DB.mapCalibration;

    moveListRef.current = devices.map(d => {
      // 2D 픽셀 좌표 -> 3D 월드 좌표 변환 (정밀 캘리브레이션 적용)
      const normX = (d.x - offsetX) / scale * (invX ? -1 : 1);
      const normZ = (d.y - offsetY) / scale * (invY ? -1 : 1);
      
      return {
        id: d.id,
        point: { x: normX, y: d.z || 0, z: normZ }
      };
    });
  }, [devices]);

  const setupInProgress = useRef(false);

  useEffect(() => {
    if (!containerRef.current || setupInProgress.current) return;

    const setup = async () => {
      setupInProgress.current = true;
      if (!containerRef.current) return;

      try {
        if (containerRef.current) containerRef.current.innerHTML = '';
        const engine = new QuarantineThreeEngine(containerRef.current!);
        engineRef.current = engine;
        
        // [SYNC-COORDINATES] 데이터 정규화 및 시뮬레이션 초기 위치 동기화
        const { offsetX, offsetY, scale, invX, invY } = QUARANTINE_DB.mapCalibration;
        const normalizedDevicesData = QUARANTINE_DB.devices.map(d => {
          const normX = (d.x - offsetX) / scale * (invX ? -1 : 1);
          const normZ = (d.y - offsetY) / scale * (invY ? -1 : 1);
          return { ...d, x: normX, z: normZ, y: d.z || 0 };
        });

        // 미끄러짐 방지: 시뮬레이션의 시작 지점을 현재 장비 위치로 강제 일치
        moveListRef.current = normalizedDevicesData.map(d => ({
          id: d.id,
          point: { x: d.x, y: d.y, z: d.z }
        }));

        await engine.loadAllAssets(
            QUARANTINE_DB.mapConfig.modelFile, 
            normalizedDevicesData, 
            QUARANTINE_DB.mapConfig.baseUrl, 
            QUARANTINE_DB.mapConfig.equipBaseUrl
        );
        
        // [CINEMATIC-INTRO] 최초 로딩 완료 후 전체 조감도로 줌인하며 회전 시작
        setTimeout(() => {
          if (engineRef.current && !selectedEquipment) {
            engineRef.current.interaction.jumpTo(0, 0, 0, 800); // 전체 조감도 위치로 줌인
            engineRef.current.interaction.startShowcase(); // 360도 회전 애니메이션 시작
          }
        }, 1000);
        
        if (containerRef.current) {
          containerRef.current.addEventListener("pointermove", onPointerMove);
          containerRef.current.addEventListener("pointerdown", onMouseClick);
        }
        
        window.addEventListener("reset-3d-camera", () => engineRef.current?.fitView());
        window.addEventListener("zoom-in-3d", () => engineRef.current?.zoom(1.2));
        window.addEventListener("zoom-out-3d", () => engineRef.current?.zoom(0.8));
        requestAnimationFrame(animate);
      } catch (err) {
        console.error("[3D] FATAL ERROR:", err);
      }
    };
    setup();

    return () => {
      setupInProgress.current = false;
      engineRef.current?.dispose();
    };
  }, []);

  const moveDeviceLogic = (sceneDevice: any, targetPoint: any) => {
    const dist = Math.sqrt(Math.pow(sceneDevice.position.x - targetPoint.x, 2) + Math.pow(sceneDevice.position.z - targetPoint.z, 2));
    if (dist > 0.01) {
      // [SMOOTH-LERP] 속도가 느려진 만큼 보간을 더 정교하게 처리 (1.0 대기 시간을 0.8로 최적화하여 반응성 확보)
      sceneDevice.position.x += (targetPoint.x - sceneDevice.position.x) / (0.8 * fpsLimit);
      sceneDevice.position.z += (targetPoint.z - sceneDevice.position.z) / (0.8 * fpsLimit);
      
      // 이동 방향을 바라보도록 회전 처리 추가 (Realism)
      const angle = Math.atan2(targetPoint.x - sceneDevice.position.x, targetPoint.z - sceneDevice.position.z);
      sceneDevice.rotation.y = THREE.MathUtils.lerp(sceneDevice.rotation.y, angle, 0.1);
    }
  };

  const animate = useCallback((time: number) => {
    if (!aniFlagRef.current || !engineRef.current) return;
    requestAnimationFrame(animate);

    const delta = time - lastRenderTime.current;
    if (delta < (1000 / fpsLimit)) return; 
    lastRenderTime.current = time;

    // [EDIT-MODE-GARD] 편집 중에는 시뮬레이션 정지
    if (isEditModeRef.current) return;

    const { scene } = engineRef.current;
    moveListRef.current.forEach(moveItem => {
      scene.children.forEach((sceneDevice: any) => {
        if (sceneDevice.userData?.id && moveItem.id === sceneDevice.userData.id) {
          if (cameraPointRef.current.view === "device" && cameraPointRef.current.id === sceneDevice.userData.id) {
            engineRef.current!.trackDevice(sceneDevice.position.x, sceneDevice.position.y, sceneDevice.position.z);
          }
          moveDeviceLogic(sceneDevice, moveItem.point);
        }
      });
    });
  }, []);

  const onPointerMove = (event: any) => {
    if (!containerRef.current || !engineRef.current) return;
    let objChild = engineRef.current.getDeviceObjects();
    const rect = containerRef.current.getBoundingClientRect();
    pointerRef.current.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    pointerRef.current.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
    
    const intersects = engineRef.current.pick(pointerRef.current, objChild);
    if (intersects.length > 0) {
      let target: any = intersects[0].object;
      while(target && target.userData?.type !== 'device') target = target.parent;
      if (target) {
        preObjRef.current = target; 
        if (preObjRef.current.userData?.id !== clickedObjRef.current.id) {
          target.traverse((el: any) => { if (el.isMesh && el.material) el.material.color = colors.current.red; });
        }
      }
    } else if (preObjRef.current.userData?.id) {
      if (preObjRef.current.userData?.id !== clickedObjRef.current.id) {
         preObjRef.current.traverse((child: any) => { if (child.isMesh && child.material) child.material.color = colors.current.white; });
      }
      preObjRef.current = {};
    }
  };

  const onMouseClick = () => {
    if (!engineRef.current) return;
    let objChild = engineRef.current.getDeviceObjects();
    const intersects = engineRef.current.pick(pointerRef.current, objChild);

    if (intersects.length > 0) {
      let target: any = intersects[0].object;
      while(target && target.userData?.type !== 'device') target = target.parent;
      if (target) {
        if (isEditModeRef.current) engineRef.current.attachGizmo(target);
        
        const selectedItem = QUARANTINE_DB.devices.find(d => d.id === target.userData.id);
        if (onDeviceSelect && selectedItem && !isEditModeRef.current) {
          onDeviceSelect({
              ...selectedItem,
              type: target.userData.id?.includes('R-') ? "지능형 로봇" : "자동화 기기",
              icon: `/assets/platforms/quarantine/equipment/${selectedItem.deviceGrpCd}`
          });
        }
      }
    } else {
      engineRef.current.detachGizmo();
      if (clickedObjRef.current.id) onDeviceSelect?.(null);
    }
  };

  const btnCameraClick = () => {
    if (!engineRef.current) return;
    if (cameraPoint.view === "device") {
      setCameraPoint({ view: "map", id: "" });
      setBtnContent("btnMap");
      changeOriginalColor(); 
      clickedObjRef.current = {};
      engineRef.current.fitView();
      onDeviceSelect?.(null);
    } else {
      // [VIEW-FIX] 강제로 첫 번째 장비를 선택하던 로직 제거
      // 사용자가 직접 장비를 선택하기 전까지는 전체 보기(Total View) 유지
      engineRef.current.fitView();
    }
  };

  return (
    <div className="w-full h-full relative group overflow-hidden bg-slate-900">
      <div ref={containerRef} className="w-full h-full cursor-grab active:cursor-grabbing" />
      <div className="absolute top-6 right-32 z-30">
        <Space orientation="vertical" align="end" size="middle">
          <Button
            className="transition-all duration-300 shadow-xl border-none hover:scale-105 active:scale-95"
            style={{ 
              width: 120, height: 40,
              background: isEditMode ? token.colorError : token.colorSuccess,
              color: token.colorTextLightSolid, fontWeight: "bold", borderRadius: "8px"
            }}
            onClick={() => {
              if (isEditMode && engineRef.current) {
                // [SAVE-LOGIC] 편집 완료 시 씬의 현재 좌표를 DB에 반영
                const deviceObjects = engineRef.current.getDeviceObjects();
                deviceObjects.forEach((obj: any) => {
                  if (obj.userData?.id) {
                    const dbDevice = QUARANTINE_DB.devices.find(d => d.id === obj.userData.id);
                    if (dbDevice) {
                      const { offsetX, offsetY, scale, invX, invY } = QUARANTINE_DB.mapCalibration;
                      // 3D 월드 좌표 -> 시스템 좌표 역정규화
                      dbDevice.x = (obj.position.x * (invX ? -1 : 1) * scale) + offsetX;
                      dbDevice.y = (obj.position.z * (invY ? -1 : 1) * scale) + offsetY;
                      dbDevice.z = obj.position.y;
                      
                      // 시뮬레이션 이동 목표(moveList)도 즉시 동기화하여 미끄러짐 방지
                      const moveItem = moveListRef.current.find(m => m.id === dbDevice.id);
                      if (moveItem) {
                        moveItem.point = { x: obj.position.x, y: obj.position.y, z: obj.position.z };
                      }
                    }
                  }
                });
                console.log("[3D] All equipment coordinates saved to QUARANTINE_DB.");
              }
              setIsEditMode(!isEditMode);
            }}
          >
            {isEditMode ? t("simulation.btnEditDone") : t("simulation.btnEdit")}
          </Button>
          <Button
            className="transition-all duration-300 shadow-xl border-none hover:scale-105 active:scale-95"
            style={{ 
              width: 120, height: 40,
              background: showDebug ? "#f5222d" : "#13c2c2",
              color: "#fff", fontWeight: "bold", borderRadius: "8px"
            }}
            onClick={() => setShowDebug(!showDebug)}
          >
             {showDebug ? t("simulation.debugOff") : t("simulation.debugOn")}
          </Button>
          <Button
            className="transition-all duration-300 shadow-xl border-none hover:scale-105 active:scale-95"
            style={{ 
              width: 120, height: 40,
              background: btnContent === "btnMap" ? token.colorPrimary : token.colorBgElevated,
              color: btnContent === "btnMap" ? token.colorTextLightSolid : token.colorText,
              fontWeight: "bold", borderRadius: "8px"
            }}
            onClick={btnCameraClick}
          >
            {btnContent === "btnMap" ? t("simulation.btnViewDevice") : t("simulation.btnViewTotal")}
          </Button>
        </Space>
      </div>
    </div>
  );
};

export default Placement3DPage;
