import * as THREE from 'three';

/**
 * LightingSystem: 씬의 광원과 분위기를 관리합니다.
 */
export default class LightingSystem {
  private scene: THREE.Scene;

  constructor(scene: THREE.Scene) {
    this.scene = scene;
    this.setupLights();
  }

  private setupLights() {
    // 1. Hemisphere Light (균형 잡힌 전체 백색광)
    const hemiLight = new THREE.HemisphereLight(0xffffff, 0x888888, 1.8);
    hemiLight.position.set(0, 1000, 0);
    this.scene.add(hemiLight);
 
    // 2. Main Directional Light (강력한 정면 조명)
    const dirLight = new THREE.DirectionalLight(0xffffff, 2.0);
    dirLight.position.set(500, 1500, 500);
    dirLight.castShadow = true;
    
    // 그림자 설정
    dirLight.shadow.mapSize.width = 2048;
    dirLight.shadow.mapSize.height = 2048;
    this.scene.add(dirLight);
 
    // 3. Fill Light (백색 보조광 - 입체감 보충)
    const fillLight = new THREE.DirectionalLight(0xffffff, 1.0);
    fillLight.position.set(-500, 500, -500);
    this.scene.add(fillLight);
  }

  public updateBackground(color: number) {
    this.scene.background = new THREE.Color(color);
  }
}
