import * as THREE from 'three';
import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';

/**
 * MapManager: 3D 지형 및 건물 모델 로딩을 전담합니다.
 */
export default class MapManager {
  private loader: GLTFLoader;
  private scene: THREE.Scene;
  public mapModel: THREE.Group | null = null;

  constructor(scene: THREE.Scene) {
    this.scene = scene;
    this.loader = new GLTFLoader();
  }

  /**
   * [STRICT-BOX] 실제 메시(Mesh)들만의 바운딩 박스를 계산 (유령 노드 제거)
   */
  public calculateStrictBounds(): THREE.Box3 {
    console.log("[MapManager] Calculating Strict Bounds...");
    const strictBox = new THREE.Box3();
    if (!this.mapModel) {
        console.warn("[MapManager] mapModel is null!");
        return strictBox;
    }

    let hasMesh = false;
    let meshCount = 0;
    this.mapModel.updateMatrixWorld(true);
    
    this.mapModel.traverse((child: any) => {
      if (child.isMesh) {
          meshCount++;
          child.geometry.computeBoundingBox();
          const childBox = child.geometry.boundingBox.clone();
          childBox.applyMatrix4(child.matrixWorld);
          
          if (hasMesh) {
              strictBox.union(childBox);
          } else {
              strictBox.copy(childBox);
              hasMesh = true;
          }
      }
    });

    const size = new THREE.Vector3();
    strictBox.getSize(size);
    console.log(`[MapManager] Found ${meshCount} meshes. Result Size:`, size, "Center:", strictBox.getCenter(new THREE.Vector3()));
    
    return strictBox;
  }

  /**
   * 맵 에셋 로드
   */
  public async loadMap(modelFile: string, baseUrl: string, scale: number = 100) {
    const mapUrl = `${baseUrl}${modelFile}`;
    console.log(`[MapManager] Loading Map: ${mapUrl} with scale: ${scale}`);
    
    try {
      const gltf = await this.loader.loadAsync(mapUrl);
      this.mapModel = gltf.scene;
      
      // 1. 데이터 기반 스케일 설정
      this.mapModel.scale.set(scale, scale, scale);
      this.mapModel.updateMatrixWorld(true);
      
      // 2. [STRICT-BOX] 실제 메시(Mesh)들만의 바운딩 박스를 계산 (유령 노드 제거)
      const strictBox = new THREE.Box3();
      let hasMesh = false;
      
      this.mapModel.traverse((child: any) => {
        if (child.isMesh) {
            child.geometry.computeBoundingBox();
            const childBox = child.geometry.boundingBox.clone();
            childBox.applyMatrix4(child.matrixWorld);
            
            // 너무 멀리 떨어진 비정상적인 노드는 제외 (필요 시)
            if (hasMesh) {
                strictBox.union(childBox);
            } else {
                strictBox.copy(childBox);
                hasMesh = true;
            }
        }
      });
      
      // 3. 렌더링 최적화 적용
      this.optimize(this.mapModel);
      
      // 4. 강제 중앙 정렬 (순수 메시 중심 기준)
      if (hasMesh) {
          const center = new THREE.Vector3();
          strictBox.getCenter(center);
          
          // 현재 위치에서 순수 장치 중심만큼을 뺌
          this.mapModel.position.sub(center);
          this.mapModel.position.y = 0; // 바닥면 접지
      }
      
      this.scene.add(this.mapModel);
      return this.mapModel;
    } catch (err) {
      console.error("[MapManager] Map load failed", err);
      throw err;
    }
  }

  private optimize(obj: THREE.Object3D) {
    obj.traverse((child: any) => {
      if (child.isMesh) {
        child.layers.set(0);
        if (child.material) {
          child.material.side = THREE.DoubleSide;
          child.material.depthWrite = true;
          child.receiveShadow = true;
        }
      }
    });
  }

  public dispose() {
    if (this.mapModel) {
      this.scene.remove(this.mapModel);
      this.mapModel = null;
    }
  }
}
