import * as THREE from 'three';
import { GLTFLoader } from 'three/addons/loaders/GLTFLoader.js';

/**
 * EquipmentManager: 로봇, 보안 장비 등 시뮬레이션 자산 로딩 및 관리를 전담합니다.
 */
export default class EquipmentManager {
  private loader: GLTFLoader;
  private scene: THREE.Scene;
  public devices: Map<string, THREE.Group> = new Map();

  constructor(scene: THREE.Scene) {
    this.scene = scene;
    this.loader = new GLTFLoader();
  }

  /**
   * 여러 장비 일괄 로드
   */
  public async loadDevices(devicesData: any[], baseUrl: string) {
    console.log(`[EquipmentManager] Loading ${devicesData.length} devices...`);

    const promises = devicesData.map(async (d) => {
      // 1. modelFile이 있으면 그대로 사용 (확장자 중복 방지), 없으면 deviceGrpCd에 .glb 붙여서 사용
      const fileName = d.modelFile ? d.modelFile : `${d.deviceGrpCd}.glb`;
      const dUrl = `${baseUrl}${fileName}`;
      
      console.log(`[EquipmentManager] Loading: ${d.name} from ${dUrl}`);
      try {
        const gltf = await this.loader.loadAsync(dUrl);
        const obj = gltf.scene;

        // 1. 메타데이터 및 속성 설정
        obj.name = d.name;
        obj.userData = {
          id: d.id,
          type: 'device',
          deviceGrpCd: d.deviceGrpCd
        };

        // 2. 스케일 및 재질 최적화
        const scale = d.scale || 2;
        obj.scale.set(scale, scale, scale);
        this.optimize(obj);

        // 3. 배치 위치 계산 (기본 접지 오프셋 + DB 높이값 반영)
        const dbox = new THREE.Box3().setFromObject(obj);
        const altitude = d.y || 0;
        obj.position.set(d.x, altitude - dbox.min.y, d.z);

        // 4. 장면 추가 및 관리 맵 등록
        this.devices.set(d.id, obj);
        this.scene.add(obj);

        return obj;
      } catch (err) {
        console.error(`[EquipmentManager] Failed to load device: ${d.name}`, err);
        return null;
      }
    });

    return await Promise.all(promises);
  }

  /**
   * 특정 장비 객체 가져오기
   */
  public getDeviceById(id: string) {
    return this.devices.get(id);
  }

  /**
   * 장비 객체 목록 추출 (인터랙션 피킹용)
   */
  public getDeviceObjects() {
    return Array.from(this.devices.values());
  }

  private optimize(obj: THREE.Object3D) {
    obj.traverse((child: any) => {
      if (child.isMesh) {
        child.castShadow = true;
        child.receiveShadow = true;
        if (child.material) {
          child.material.side = THREE.DoubleSide;
          child.material.depthWrite = true;
        }
      }
    });
  }

  public dispose() {
    this.devices.forEach((obj) => {
      this.scene.remove(obj);
    });
    this.devices.clear();
  }
}
