import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
import { TransformControls } from 'three/examples/jsm/controls/TransformControls.js';

/**
 * InteractionManager: 사용자 입력, 카메라 컨트롤, 기즈모 조작을 통합 관리합니다.
 */
export default class InteractionManager {
  public controls: OrbitControls;
  public transformControls: TransformControls;
  public raycaster: THREE.Raycaster;
  private gizmoScene: THREE.Scene;
  private camera: THREE.PerspectiveCamera;
  private currentBaseSize: number = 1.0;
  private domElement: HTMLElement;

  private targetSpherical = new THREE.Spherical();
  private currentSpherical = new THREE.Spherical();
  private targetLookAt: THREE.Vector3 | null = null;
  public isTransitioning: boolean = false;
  private lerpFactor: number = 0.08; // 전이 속도 약간 상향

  private targetFilmOffset: number = 0;

  // Real-time Selection Label
  private selectionLabel: THREE.Sprite | null = null;
  private labelCanvas = document.createElement('canvas');
  private labelTexture: THREE.CanvasTexture | null = null;

  // Showcase/Debug State
  private isShowcasing: boolean = false;
  private showcaseTotalAngle: number = 0;
  private lastAzimuth: number = 0;
  private deviceRawCenter: THREE.Vector3 = new THREE.Vector3();
  
  public debugInfo = {
    pos: new THREE.Vector3(),
    target: new THREE.Vector3(),
    dist: 0,
    selectedPos: new THREE.Vector3(),
    selectedId: ""
  };

  constructor(camera: THREE.PerspectiveCamera, domElement: HTMLElement) {
    this.camera = camera;
    this.domElement = domElement;
    this.gizmoScene = new THREE.Scene();
    this.raycaster = new THREE.Raycaster();

    this.controls = new OrbitControls(this.camera, this.domElement);
    this.controls.enableDamping = true;
    this.controls.dampingFactor = 0.05;

    this.controls.addEventListener('start', () => {
      this.isTransitioning = false;
      this.stopShowcase();
    });

    this.transformControls = new TransformControls(this.camera, this.domElement);
    this.gizmoScene.add(new THREE.AmbientLight(0xffffff, 1.0));
    
    // [THREE-R183-FIX] 최신 버전에서는 controls 자체가 아닌 getHelper()를 씬에 추가해야 함
    const helper = this.transformControls.getHelper();
    this.gizmoScene.add(helper as unknown as THREE.Object3D);

    // [GIZMO-ALWAYS-ON-TOP] 기즈모가 지형이나 객체에 가려지지 않도록 최상단 노출 처리
    helper.traverse((child: any) => {
      if (child.material) {
        child.material.depthTest = false;
        child.material.depthWrite = false;
        child.material.transparent = true;
        child.material.side = THREE.DoubleSide;
      }
      child.renderOrder = 9999;
    });

    // [SELECTION-LABEL] 실시간 좌표 라벨 설정
    this.labelCanvas.width = 512;
    this.labelCanvas.height = 128;
    this.labelTexture = new THREE.CanvasTexture(this.labelCanvas);
    const spriteMaterial = new THREE.SpriteMaterial({ 
        map: this.labelTexture, 
        transparent: true, 
        depthTest: false,
        sizeAttenuation: true
    });
    this.selectionLabel = new THREE.Sprite(spriteMaterial);
    this.selectionLabel.scale.set(4, 1, 1); // [BALANCED-LABEL] 가독성을 위해 적정 크기 유지
    this.selectionLabel.visible = false;
    this.gizmoScene.add(this.selectionLabel);

    // [REAL-TIME-TELEMETRY] 장비 이동 시 좌표 실시간 추적 및 라벨 갱신
    this.transformControls.addEventListener('change', () => {
        if (this.transformControls.object) {
            const pos = this.transformControls.object.position;
            this.debugInfo.selectedPos.copy(pos);
            this.debugInfo.selectedId = this.transformControls.object.userData?.id || "UNKNOWN";
            
            // 라벨 위치를 장비 바로 위로 밀착
            const target = this.transformControls.object;
            const heightOffset = (target.scale.y * 1.0) + 2; 
            this.selectionLabel!.position.set(pos.x, pos.y + heightOffset, pos.z);
            this.selectionLabel!.visible = true;
            this.updateLabelUI();
        }
    });

    this.transformControls.addEventListener('dragging-changed', (event: any) => {
      this.controls.enabled = !event.value;
    });
  }

  /**
   * 장비 머리 위 라벨 디자인 업데이트 (HUD 프리미엄 디자인)
   */
  private updateLabelUI() {
    if (!this.labelTexture) return;
    const ctx = this.labelCanvas.getContext('2d');
    if (!ctx) return;

    const { selectedId, selectedPos } = this.debugInfo;
    
    // 시스템 좌표로 정규화 (0~1000 스케일)
    const normX = (selectedPos.x * 10) + 500;
    const normY = (selectedPos.z * 10) + 300;
    const normZ = selectedPos.y;

    ctx.clearRect(0, 0, 512, 128);
    
    // 1. 메인 배경 (Dark Crystal Style)
    const gradient = ctx.createLinearGradient(0, 0, 0, 128);
    gradient.addColorStop(0, 'rgba(15, 23, 42, 0.95)');
    gradient.addColorStop(1, 'rgba(30, 41, 59, 0.98)');
    ctx.fillStyle = gradient;
    
    ctx.beginPath();
    ctx.roundRect(5, 5, 502, 118, 12);
    ctx.fill();

    // 2. 내부 위광 및 테두리 (Cyber Accent)
    ctx.strokeStyle = 'rgba(56, 189, 248, 0.5)'; // Cyan Glow
    ctx.lineWidth = 2;
    ctx.stroke();
    
    // 상단 포인트 라인
    ctx.strokeStyle = '#38bdf8';
    ctx.beginPath();
    ctx.moveTo(20, 5);
    ctx.lineTo(100, 5);
    ctx.stroke();

    // 3. 좌측 구획 (ID 영역)
    ctx.fillStyle = '#38bdf8';
    ctx.font = 'bold 22px Inter, Arial';
    ctx.fillText('DEVICE ID', 30, 40);
    
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 48px Inter, Arial';
    ctx.fillText(selectedId, 30, 90);

    // 4. 수직 구분선
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
    ctx.beginPath();
    ctx.moveTo(210, 20);
    ctx.lineTo(210, 108);
    ctx.stroke();

    // 5. 우측 구획 (Telemetry 정보)
    // 3D 좌표 (Cyan)
    ctx.font = '18px Inter, Arial';
    ctx.fillStyle = '#7dd3fc';
    ctx.fillText('3D WORLD COORD', 235, 35);
    
    ctx.font = 'bold 26px monospace';
    ctx.fillStyle = '#e2e8f0';
    ctx.fillText(`X:${selectedPos.x.toFixed(1)} Y:${selectedPos.y.toFixed(1)} Z:${selectedPos.z.toFixed(1)}`, 235, 65);

    // MAP 좌표 (Yellow)
    ctx.font = '18px Inter, Arial';
    ctx.fillStyle = '#fbbf24';
    ctx.fillText('MAP SYSTEM DATA', 235, 88);
    
    ctx.font = 'bold 26px monospace';
    ctx.fillStyle = '#fef3c7';
    ctx.fillText(`X:${normX.toFixed(0)} Y:${normY.toFixed(0)} Z:${normZ.toFixed(1)}`, 235, 115);

    this.labelTexture.needsUpdate = true;
  }

  public setEditMode(isEdit: boolean) {
    // [EDIT-MODE-CLEANUP] 모드 전환 시점에 강제로 보이게 하지 않음
    // 대신 attach()와 detach()가 호출될 때 자동으로 visible이 관리되도록 내버려둠
    if (!isEdit) this.detach();
  }

  private stopShowcase() {
    this.isShowcasing = false;
    this.controls.autoRotate = false;
  }

  public pick(pointer: THREE.Vector2, objects: THREE.Object3D[]) {
    this.raycaster.setFromCamera(pointer, this.camera);
    return this.raycaster.intersectObjects(objects, true);
  }

  public trackTo(x: number, y: number, z: number, offset: number = 0) {
    this.deviceRawCenter.set(x, y, z);
    this.targetFilmOffset = offset; // 5로 나누던 로직 제거 (직관적인 수치 적용)
    this.targetLookAt = new THREE.Vector3(x, y, z);
  }

  public jumpTo(x: number, y: number, z: number, dist: number = 500, offset: number = 0) {
    const newTarget = new THREE.Vector3(x, y, z);
    // [NULL-GUARD] 최초 호출 시 targetLookAt이 null일 수 있으므로 대응
    const targetDiff = this.targetLookAt ? newTarget.distanceTo(this.targetLookAt) : 999;

    // [DYNAMIC-RESYNC] 타겟이 바뀌거나 새로 시작하는 경우 현재 상태에서 다시 계산
    if (!this.isTransitioning || targetDiff > 5) {
        console.log(`[Interaction] Resyncing Camera for Target Change. Dist to new target: ${targetDiff.toFixed(1)}`);
        
        // 현재 카메라 위치를 '새로운 타겟' 기준의 구형 좌표로 변환하여 자연스러운 출발점 확보
        const offsetVec = new THREE.Vector3().subVectors(this.camera.position, newTarget);
        this.currentSpherical.setFromVector3(offsetVec);
        
        // 즉시 전이 목표 설정
        this.trackTo(x, y, z, offset);
    }

    // 타겟 구형 좌표 설정
    const direction = new THREE.Vector3(1, 0.8, 1).normalize();
    const targetPos = direction.multiplyScalar(dist);
    this.targetSpherical.setFromVector3(targetPos);
    
    this.isTransitioning = true;
    
    // [SHOWCASE-LOGIC] 거리와 관계없이 인위적으로 쇼케이스를 트리거할 수 있도록 수정
    if (dist < 300) {
      this.startShowcase();
    } else {
      this.stopShowcase();
    }
  }

  public startShowcase() {
    this.isShowcasing = true;
    this.showcaseTotalAngle = 0;
    this.lastAzimuth = this.controls.getAzimuthalAngle();
    this.controls.autoRotate = true;
    this.controls.autoRotateSpeed = 4.0; // 시네마틱한 속도
  }

  public update() {
    // [REAL-TIME-GIZMO-RESIZE] 카메라 거리에 따라 기즈모 크기를 역산하여 월드 스케일 고정
    if (this.transformControls.object) {
        const dist = this.camera.position.distanceTo(this.transformControls.object.position);
        // TransformControls 내부의 size attenuation을 상쇄하기 위해 거리로 나눔
        // 장비 바운딩 박스 크기(currentBaseSize)에 비례하도록 실시간 보정
        this.transformControls.size = (this.currentBaseSize / dist) * 12.0; 
    }

    // Debug Info 갱신
    this.debugInfo.pos.copy(this.camera.position);
    this.debugInfo.target.copy(this.controls.target);
    this.debugInfo.dist = this.camera.position.distanceTo(this.controls.target);

    // 카메라 필름 오프셋 애니메이션
    if (Math.abs(this.camera.filmOffset - this.targetFilmOffset) > 0.01) {
        this.camera.filmOffset = THREE.MathUtils.lerp(this.camera.filmOffset, this.targetFilmOffset, this.lerpFactor);
        this.camera.updateProjectionMatrix();
    }

    if (this.isTransitioning && this.targetLookAt) {
      // 1. 타겟(Center) 부드럽게 이동
      this.controls.target.lerp(this.targetLookAt, this.lerpFactor);
      
      // 2. 구형 좌표(Radius, Phi, Theta) 보간
      this.currentSpherical.radius = THREE.MathUtils.lerp(this.currentSpherical.radius, this.targetSpherical.radius, this.lerpFactor);
      this.currentSpherical.phi = THREE.MathUtils.lerp(this.currentSpherical.phi, this.targetSpherical.phi, this.lerpFactor);
      
      let diff = this.targetSpherical.theta - this.currentSpherical.theta;
      while (diff < -Math.PI) diff += Math.PI * 2;
      while (diff > Math.PI) diff -= Math.PI * 2;
      this.currentSpherical.theta += diff * this.lerpFactor;
      
      // 3. [ORBIT-FORCE] 보간된 구형 좌표를 카메라 위치로 역산하여 적용
      const newRelativePos = new THREE.Vector3().setFromSpherical(this.currentSpherical);
      this.camera.position.copy(newRelativePos).add(this.controls.target);
      
      // 4. 전이 완료 체크
      if (this.controls.target.distanceTo(this.targetLookAt) < 0.5 && 
          Math.abs(this.currentSpherical.radius - this.targetSpherical.radius) < 0.5) {
        this.isTransitioning = false;
      }
      
      // [CRITICAL] 위에서 강제로 바꾼 카메라 위치를 OrbitControls에 동기화
      this.controls.update(); 
      return; 
    }

    if (this.isShowcasing && !this.isTransitioning) {
      this.controls.autoRotate = true;
      const currentAzimuth = this.controls.getAzimuthalAngle();
      let delta = currentAzimuth - this.lastAzimuth;
      if (delta > Math.PI) delta -= Math.PI * 2;
      if (delta < -Math.PI) delta += Math.PI * 2;
      this.showcaseTotalAngle += Math.abs(delta);
      this.lastAzimuth = currentAzimuth;
      if (this.showcaseTotalAngle >= Math.PI * 1.95) { 
        this.stopShowcase();
      }
    }

    this.controls.update();
  }

  public renderGizmo(renderer: THREE.WebGLRenderer) {
    if (this.transformControls.getHelper().visible) {
      renderer.autoClear = false;
      renderer.clearDepth();
      renderer.render(this.gizmoScene, this.camera);
      renderer.autoClear = true;
    }
  }

  public attach(obj: THREE.Object3D) {
    this.transformControls.attach(obj);
    
    // [BBOX-SIZE-CAPTURE] 실제 바운딩 박스 크기를 기준값으로 저장
    const box = new THREE.Box3().setFromObject(obj);
    const size = new THREE.Vector3();
    box.getSize(size);
    this.currentBaseSize = Math.max(size.x, size.y, size.z);
    
    // 즉시 크기 적용
    this.transformControls.size = (this.currentBaseSize / this.camera.position.distanceTo(obj.position)) * 12.0;
  }

  public detach() {
    this.transformControls.detach();
    if (this.selectionLabel) this.selectionLabel.visible = false;
  }
}
