import * as THREE from 'three';

/**
 * WebGLBase: Three.js의 핵심 렌더링 기반을 담당합니다.
 */
export default class WebGLBase {
  public scene: THREE.Scene;
  public camera: THREE.PerspectiveCamera;
  public renderer: THREE.WebGLRenderer;
  private container: HTMLElement;
  private resizeObserver: ResizeObserver | null = null;

  constructor(container: HTMLElement) {
    this.container = container;
    this.scene = new THREE.Scene();

    this.renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    this.renderer.setPixelRatio(window.devicePixelRatio);
    
    // 기본 색공간 및 그림자 설정
    (this.renderer as any).outputColorSpace = THREE.SRGBColorSpace;
    this.renderer.shadowMap.enabled = true;
    this.renderer.shadowMap.type = THREE.PCFShadowMap;
    this.renderer.toneMapping = THREE.ACESFilmicToneMapping;
    this.renderer.toneMappingExposure = 1.0;

    this.container.appendChild(this.renderer.domElement);

    this.camera = new THREE.PerspectiveCamera(40, container.clientWidth / container.clientHeight, 1, 100000);
    this.camera.position.set(2000, 1500, 2000);

    // [DYNAMIC-RESIZE] 사이드바 토글 등 컨테이너 크기 변화를 감지하는 관찰자 등록
    this.setupResizeObserver();
    
    this.updateSize();
  }

  /**
   * ResizeObserver를 사용하여 DOM 엘리먼트의 실제 크기 변화를 실시간 감지
   */
  private setupResizeObserver() {
    this.resizeObserver = new ResizeObserver(() => {
        this.updateSize();
    });
    this.resizeObserver.observe(this.container);
  }

  public updateSize() {
    if (!this.container || !this.renderer) return;
    
    const width = this.container.clientWidth;
    const height = this.container.clientHeight;
    
    if (width === 0 || height === 0) return;

    this.renderer.setSize(width, height);
    if (this.camera) {
      this.camera.aspect = width / height;
      this.camera.updateProjectionMatrix();
    }
    
    console.log(`[WebGLBase] Size Updated: ${width}x${height}`);
  }

  public render() {
    this.renderer.render(this.scene, this.camera);
  }

  public dispose() {
    if (this.resizeObserver) {
        this.resizeObserver.disconnect();
        this.resizeObserver = null;
    }
    this.renderer.dispose();
  }
}
